customCSS:
/* Autumn Harvest - Forest Canopy Background */
@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;600;700&family=Lato:wght@300;400;700&family=IBM+Plex+Mono&display=swap');

/* Static warm autumn gradient background */
.cyber-grid {
  background: none;
  animation: none;
}

.cyber-glow {
  background: 
    radial-gradient(ellipse at 15% 25%, rgba(234, 88, 12, 0.18) 0%, transparent 40%),
    radial-gradient(ellipse at 85% 20%, rgba(217, 119, 6, 0.12) 0%, transparent 35%),
    radial-gradient(ellipse at 50% 75%, rgba(132, 204, 22, 0.08) 0%, transparent 45%),
    linear-gradient(180deg, rgba(132, 204, 22, 0.05) 0%, rgba(217, 119, 6, 0.08) 50%, rgba(234, 88, 12, 0.1) 100%);
  animation: none;
}

.cyber-particles { display: none; }

.stat-card {
  border-radius: 10px;
  border: 1px solid rgba(234, 88, 12, 0.25);
}

.stat-card::before {
  background: linear-gradient(135deg, #84cc16, #d97706, #ea580c, #dc2626);
}

.stat-card:hover {
  box-shadow: 0 0 25px rgba(234, 88, 12, 0.25);
}

.celebration-title {
  background: linear-gradient(135deg, #84cc16, #d97706, #ea580c, #dc2626);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
}

.miner-card, .health-card, .lifetime-card { border-radius: 10px; }
